// Dummy users data for demo purposes
const users = [
  { username: 'john', password: 'password1' },
  { username: 'jane', password: 'password2' }
];

// Dummy session middleware for demo purposes
app.use((req, res, next) => {
  // Simulate session authentication
  req.session = { loggedIn: true, username: 'john' }; // Set session for demo user
  next();
});

app.post('/delete-account', (req, res) => {
  const { password } = req.body;

  if (!password) {
    return res.status(400).send('Password is required');
  }

  const user = users.find(u => u.username === req.session.username);

  if (!user) {
    return res.status(404).send('User not found');
  }

  if (password !== user.password) {
    return res.status(401).send('Unauthorized');
  }

  // Delete account logic here
  // For demo purposes, just sending success response
  return res.send('Account deleted successfully');
});

